"use client";

import { MapContainer, TileLayer, Marker, Popup, useMap } from "react-leaflet";
import type { LatLngExpression } from "leaflet";

function SetViewOnMount({ position }: { position: LatLngExpression }) {
  const map = useMap();
  map.setView(position);
  return null;
}

export default function VisitMap({
  lat,
  lng,
  name,
}: {
  lat: number | null;
  lng: number | null;
  name: string;
}) {
  if (!lat || !lng) {
    return (
      <div className="h-64 bg-slate-100 rounded-md flex items-center justify-center text-slate-400">
        位置情報が登録されていません
      </div>
    );
  }

  const position: LatLngExpression = [lat, lng];

  return (
    <MapContainer
      scrollWheelZoom={false}
      style={{ height: "260px", width: "100%", borderRadius: "12px" }}
    >
      {/* 中心座標をセット */}
      <SetViewOnMount position={position} />

      <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

      <Marker position={position}>
        <Popup>{name} さんの住所</Popup>
      </Marker>
    </MapContainer>
  );
}



